// Helper functions
export function getCareerFamilyById(id: string): CareerFamily | undefined {
  return careerFamilies.find((f) => f.id === id);
}

export function getListingsByFamily(familyId: string): CareerListing[] {
  return careerListings.filter((l) => l.familyId === familyId);
}

export function searchCareerListings(query: string): CareerListing[] {
  const q = query.toLowerCase().trim();
  if (!q) return careerListings;
  return careerListings.filter((l) =>
    l.title.toLowerCase().includes(q) ||
    l.description.toLowerCase().includes(q) ||
    l.searchTerms.some((t) => t.includes(q)) ||
    l.familyId.includes(q)
  );
}

export function getCareerListingById(id: string): CareerListing | undefined {
  return careerListings.find((l) => l.id === id);
}
